proof_block:
// Surface the destructured tuple shapes used inside both ensures conjuncts so
// z3 can line up the two `let (ok, Ghost(net_event)) = r_i` bindings on
// common names.
let ok1: bool = r1.0;
let ok2: bool = r2.0;
let ne1: Option<NetEvent> = (r1.1)@;
let ne2: Option<NetEvent> = (r2.1)@;

// Surface the two `my_end_point` ensures conjuncts and chain them transitively.
assert(post1_netc.my_end_point() == pre_netc.my_end_point());
assert(post2_netc.my_end_point() == pre_netc.my_end_point());
assert(post1_netc.my_end_point() == post2_netc.my_end_point());

// Surface the `ok <==> netc.ok()` ensures conjuncts on both runs.
assert(post1_netc.ok() <==> ok1);
assert(post2_netc.ok() <==> ok2);

// Case-split on the `ok` discriminator the spec actually pins.
if ok1 {
    assert(ne1 is Some);
    assert(post1_netc.history() == pre_netc.history() + seq![ne1.unwrap()]);
    assert(send_log_entry_reflects_packet(ne1.unwrap(), &cpacket));
    assert(is_marshalable_data(ne1.unwrap()));
    assert(ne1.unwrap() is Send);
    assert(cpacket@ == abstractify_net_packet_to_sht_packet(ne1.unwrap().arrow_Send_s()));
}
if ok2 {
    assert(ne2 is Some);
    assert(post2_netc.history() == pre_netc.history() + seq![ne2.unwrap()]);
    assert(send_log_entry_reflects_packet(ne2.unwrap(), &cpacket));
    assert(is_marshalable_data(ne2.unwrap()));
    assert(ne2.unwrap() is Send);
    assert(cpacket@ == abstractify_net_packet_to_sht_packet(ne2.unwrap().arrow_Send_s()));
}

// When both runs succeed, the abstractified projections of the two events
// coincide because both equal `cpacket@`.  This is the *only* relational
// constraint the ensures imposes between the two events.
if ok1 && ok2 {
    assert(abstractify_net_packet_to_sht_packet(ne1.unwrap().arrow_Send_s())
        == abstractify_net_packet_to_sht_packet(ne2.unwrap().arrow_Send_s()));
    assert(post1_netc.history() == post2_netc.history());
}
